mapper.select:
SELECT id AS quiz_set_id, challenge_date, variant_code, status, created_at, published_at
FROM quiz_sets ORDER BY challenge_date DESC NULLS LAST, id DESC
LIMIT #{limit} OFFSET #{offset}

mapper.delete:
DELETE FROM question_keys WHERE question_id IN (
    SELECT q.id FROM questions q JOIN passages p ON p.id = q.passage_id
    WHERE p.quiz_set_id = #{quizSetId}
)

DELETE FROM question_options WHERE question_id IN (
    SELECT q.id FROM questions q JOIN passages p ON p.id = q.passage_id
    WHERE p.quiz_set_id = #{quizSetId}
)

DELETE FROM questions WHERE passage_id IN (
    SELECT id FROM passages WHERE quiz_set_id = #{quizSetId}
)
